```typescript
useEffect(() => {
  if (state !== "idle" || !open) return

  const interval = setInterval(async () => {
    try {
      const res = await fetch(\`/api/floors/\${floorId}\`)
      const data = await res.json()
      if (data.data?.userHasMembership) {
        setState("success")
        clearInterval(interval)
        setTimeout(() => {
          onVerified()
          onOpenChange(false)
