  }, 2000)

  return () => clearInterval(interval)
}, [state, open, floorId])
```

Polls `GET /api/floors/{floorId}` every 2 seconds, checking the `userHasMembership` field (added in 3D-1). Stops on success or component unmount.

**Acceptance:** After Self verification completes (or mock is triggered), polling detects membership and transitions to success state.

**New file:** `app/api/ens/[addressOrName]/route.ts`

Public API endpoint for ENS profile resolution:

```typescript
import { NextRequest, NextResponse } from "next/server"
import { resolveEnsProfile, resolveEnsAddress } from "@/lib/web3/ens-service"
import { checksumAddress } from "@/lib/web3/address"
import { formatApiError } from "@/lib/errors"

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ addressOrName: string }> }
) {
  try {
    const { addressOrName } = await params
    let address: string

    if (addressOrName.startsWith("0x") && addressOrName.length === 42) {
      address = checksumAddress(addressOrName)
    } else {
      // Assume ENS name
      const resolved = await resolveEnsAddress(addressOrName)
      if (!resolved) {
        return NextResponse.json({ success: false, error: { code: "NOT_FOUND", message: "ENS name not found" } }, { status: 404 })
      }
      address = resolved
    }

    const profile = await resolveEnsProfile(address)
    return NextResponse.json({ success: true, data: profile })
  } catch (error) {
    return formatApiError(error)
  }
}
```

**Route:** `GET /api/ens/vitalik.eth` or `GET /api/ens/0xd8dA6BF26964aF9D7eEd9e03E53415D37aA96045`
**Auth:** Public (ENS data is public blockchain data)
**Used by:** Onboarding flow for ENS pre-population (2D-2)

**Acceptance:** Both address and ENS name inputs return profile data. Invalid inputs return 404.

