React hook implementing EIP-6963 wallet provider discovery:

```typescript
import { useState, useEffect } from "react"
import type { EIP6963ProviderDetail, EIP6963AnnounceProviderEvent } from "@/lib/web3/eip6963"

export function useWalletProviders() {
  const [providers, setProviders] = useState<EIP6963ProviderDetail[]>([])

  useEffect(() => {
    const handler = (event: Event) => {
      const e = event as EIP6963AnnounceProviderEvent
      setProviders(prev => {
        if (prev.some(p => p.info.uuid === e.detail.info.uuid)) return prev
        return [...prev, e.detail]
      })
    }

    window.addEventListener("eip6963:announceProvider", handler)
    window.dispatchEvent(new Event("eip6963:requestProvider"))

    return () => window.removeEventListener("eip6963:announceProvider", handler)
  }, [])

  return providers
}
```

This is the **specific requirement for the Moonpay OpenWallet Standard prize track** — standard-compliant wallet discovery without hardcoded connector lists.

**Existing hooks directory:** `hooks/` contains use-floors.ts, use-toast.ts, use-mobile.ts — this follows the naming convention.

**Acceptance:** Hook discovers MetaMask (or any installed EIP-6963 wallet) and returns provider details.

