Implement the full SIWE authorization flow:

```typescript
async authorize(credentials) {
  try {
    const message = credentials?.message as string
    const signature = credentials?.signature as string
    if (!message || !signature) return null

    // 1. Read + consume nonce from httpOnly cookie
    const nonce = await consumeNonce()
    if (!nonce) throw new Error("No nonce cookie found")

    // 2. Verify SIWE message
    const address = await verifySiweMessage(message, signature, nonce)

    // 3. Find or create User by walletAddress (see 1C-8)
    const user = await prisma.user.upsert({
      where: { walletAddress: address },
      update: {},
      create: { walletAddress: address },
    })

    // 4. Best-effort ENS resolution (Phase 2, non-blocking)
    // resolveEnsProfile(address) — added in 2B-1

    return {
      id: user.id,
      email: user.email,
      walletAddress: address,
      ensName: user.ensName,
      name: user.ensName ?? user.name,
    }
  } catch (e) {
    console.error("SIWE auth failed:", e)
    return null
  }
}
```

**Key:** `consumeNonce()` from lib/web3/siwe.ts. `checksumAddress()` is called inside `verifySiweMessage()`.

**Acceptance:** Signing in with a valid SIWE message creates/finds a User by walletAddress and returns a session.

